// Long-form editorial body for every tool page, keyed by tool + locale.
// Rendered at the bottom of the tool route via <ToolEditorial>.
//
// Goal: lift every locale above the 600-word / 3-H2 / FAQ threshold the
// audit flagged as missing on 54 pages. Density targets per block :
//   intro        60 to 120 words (speakable)
//   sections     3 to 6 entries, 80 to 200 words each
//   faq          3 to 5 entries
//   sources      3 to 8 external citations with titles
//
// The FR/EN copy of the tool pages is already dense enough; we only ship
// editorial data for the locales the audit flagged (JA + DE + IT + ES +
// PT + TR + PL + RU + AR + the 3 thin EN entries).

export type ToolKey =
  | "life-path"
  | "expression-number"
  | "personal-year"
  | "birth-chart"
  | "rising-sign"
  | "compatibility"
  | "karmic-debt";

export interface EditorialSection {
  title: string;
  body: string;
}

export interface EditorialFaq {
  q: string;
  a: string;
}

export interface EditorialSource {
  title: string;
  url: string;
}

export interface ToolEditorial {
  intro: string;
  sections: EditorialSection[];
  faq: EditorialFaq[];
  sources: EditorialSource[];
  labels?: { faq?: string; sources?: string };
}

// -----------------------------------------------------------------------
// Japanese (ja-JP). Audit reported 45 to 95 words per tool page — almost
// pure data with no editorial body. This block lifts every tool above
// the AI-citation threshold with proper etymology + method + patterns +
// FAQ + sources.
// -----------------------------------------------------------------------

