/** Helper for Astro pages to pull their editorial block with graceful fallback. */
export function getToolEditorial(tool: ToolKey, locale: string): ToolEditorial | null {
  const entry = TOOL_EDITORIALS[tool];
  if (!entry) return null;
  return entry[locale] ?? null;
}
